// Timezone-aware date windows using Luxon (available in n8n >= 0.214).
// Add REPORT_TIMEZONE to your n8n environment variables, e.g. 'Europe/Helsinki'.
// Falls back to UTC if the env var is absent.
const { DateTime } = require('luxon');
const tz = $env.REPORT_TIMEZONE || 'UTC';

// 'today' in the business timezone at the moment the workflow runs (Monday 08:00).
// today.weekday === 1 (ISO Monday). startOf('week') gives this week's Monday,
// minus({ weeks: 1 }) steps back to last week's Monday.
const today      = DateTime.now().setZone(tz);
const lastMonday = today.startOf('week').minus({ weeks: 1 });
const lastSunday = lastMonday.endOf('week'); // Sun 23:59:59.999 in business TZ

const fmt    = dt => dt.toISODate();                  // YYYY-MM-DD in chosen TZ
const toUnix = dt => Math.floor(dt.toMillis() / 1000);

return [{ json: {
  weekLabel: `${fmt(lastMonday)} to ${fmt(lastSunday)}`,
  timezone:  tz,
  thisWeek: {
    start:     lastMonday.toISO(),
    end:       lastSunday.toISO(),
    startUnix: toUnix(lastMonday),
    endUnix:   toUnix(lastSunday),
    startMs:   lastMonday.toMillis(),
    endMs:     lastSunday.toMillis()
  }
} }];

const startUnix = $('Compute Date Windows').first().json.thisWeek.startUnix;
const endUnix   = $('Compute Date Windows').first().json.thisWeek.endUnix;
const apiKey    = $env.STRIPE_SECRET_KEY;
const PAGE_SIZE = 100;
let allCharges  = [];
let startingAfter = null;
let hasMore = true;
while (hasMore) {
  let url = `https://api.stripe.com/v1/charges?created[gte]=${startUnix}&created[lte]=${endUnix}&limit=${PAGE_SIZE}`;
  if (startingAfter) url += `&starting_after=${startingAfter}`;
  const resp = await $http.request({ method: 'GET', url, headers: { Authorization: `Bearer ${apiKey}` }, json: true });
  const page = resp.data || [];
  allCharges = allCharges.concat(page);
  hasMore = resp.has_more === true;
  if (hasMore && page.length > 0) { startingAfter = page[page.length - 1].id; } else { hasMore = false; }
}
return [{ json: { data: allCharges, has_more: false, object: 'list' } }];

const dbId = $env.NOTION_DEALS_DB_ID;
const apiKey = $env.NOTION_API_KEY;
const startIso = $('Compute Date Windows').first().json.thisWeek.start;
const endIso = $('Compute Date Windows').first().json.thisWeek.end;
const headers = { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json', 'Notion-Version': '2022-06-28' };
let allPages = [];
let startCursor = undefined;
let hasMore = true;
while (hasMore) {
  const body = { filter: { and: [{ property: 'Created', date: { on_or_after: startIso } }, { property: 'Created', date: { on_or_before: endIso } }] }, page_size: 100 };
  if (startCursor) body.start_cursor = startCursor;
  const resp = await $http.request({ method: 'POST', url: `https://api.notion.com/v1/databases/${dbId}/query`, headers, body: JSON.stringify(body), json: true });
  allPages = allPages.concat(resp.results || []);
  hasMore = resp.has_more === true;
  startCursor = resp.next_cursor || undefined;
  if (hasMore) await new Promise(r => setTimeout(r, 350));
}
const results = allPages.map(page => { const p = page.properties || {}; return { id: page.id, properties: { amount: p['Deal Value']?.number ?? 0, dealstage: p['Stage']?.select?.name ?? 'unknown', hs_deal_stage_probability: p['Probability']?.number ?? 0, dealname: p['Name']?.title?.[0]?.plain_text ?? '' } }; });
return [{ json: { results, has_more: false, object: 'list' } }];

const dates = $('Compute Date Windows').first().json;
const stripeData = $('Stripe: This Week Revenue').first().json;
const notionData = $('Notion: Pipeline This Week').first().json;
const sheetsItems = $('GSheets: Ops Metrics').all();
const charges = stripeData.data || [];
const grossRevenue = charges.filter(c => c.status === 'succeeded' && !c.refunded).reduce((s, c) => s + c.amount, 0) / 100;
const refunds = charges.filter(c => c.refunded).reduce((s, c) => s + (c.amount_refunded || 0), 0) / 100;
const netRevenue = grossRevenue - refunds;
const newCharges = charges.filter(c => c.status === 'succeeded').length;
const deals = notionData.results || [];
const pipelineValue = deals.reduce((s, d) => s + (d.properties?.amount || 0), 0);
const weightedValue = deals.reduce((s, d) => { const amt = d.properties?.amount || 0; const prob = d.properties?.hs_deal_stage_probability || 0; return s + (amt * prob / 100); }, 0);
const dealsByStage = deals.reduce((acc, d) => { const stage = d.properties?.dealstage || 'unknown'; acc[stage] = (acc[stage] || 0) + 1; return acc; }, {});
const latestOps = sheetsItems.length > 0 ? sheetsItems[sheetsItems.length - 1].json : {};
return [{ json: { weekLabel: dates.weekLabel, revenue: { gross: grossRevenue.toFixed(2), refunds: refunds.toFixed(2), net: netRevenue.toFixed(2), transactions: newCharges }, pipeline: { dealsCreated: deals.length, totalValue: pipelineValue.toFixed(2), weightedValue: weightedValue.toFixed(2), byStage: dealsByStage }, ops: { ticketsClosed: latestOps.tickets_closed || 'N/A', npsScore: latestOps.nps_score || 'N/A', uptimePct: latestOps.uptime_pct || 'N/A', supportHours: latestOps.support_hours || 'N/A' }, generatedAt: new Date().toISOString() } }];

